const event = $input.first().json.body || $input.first().json;

// Define routing rules
const routingRules = {
  'job_created': { channels: ['telegram_admin', 'telegram_worker'], priority: 'high' },
  'job_assigned': { channels: ['telegram_worker', 'telegram_client'], priority: 'normal' },
  'job_completed': { channels: ['telegram_client', 'telegram_admin'], priority: 'normal' },
  'payment_received': { channels: ['telegram_admin', 'email_invoice'], priority: 'normal' },
  'invoice_overdue': { channels: ['telegram_admin', 'email_client'], priority: 'high' },
  'inventory_low': { channels: ['telegram_admin', 'telegram_inventory'], priority: 'high' },
  'worker_absent': { channels: ['telegram_admin'], priority: 'medium' },
  'client_feedback': { channels: ['telegram_admin', 'email_manager'], priority: 'medium' },
  'expense_submitted': { channels: ['telegram_admin'], priority: 'normal' },
  'system_alert': { channels: ['telegram_admin', 'email_admin'], priority: 'critical' }
};

const eventType = event.type || event.event_type || 'system_alert';
const rules = routingRules[eventType] || { channels: ['telegram_admin'], priority: 'normal' };

// Build message templates per channel
const templates = {
  telegram_admin: buildTelegramMessage(eventType, event, 'admin'),
  telegram_worker: buildTelegramMessage(eventType, event, 'worker'),
  telegram_client: buildTelegramMessage(eventType, event, 'client'),
  telegram_inventory: buildTelegramMessage(eventType, event, 'inventory'),
  email_invoice: buildEmailMessage(eventType, event, 'invoice'),
  email_client: buildEmailMessage(eventType, event, 'client'),
  email_manager: buildEmailMessage(eventType, event, 'manager'),
  email_admin: buildEmailMessage(eventType, event, 'admin')
};

return {
  eventType: eventType,
  priority: rules.priority,
  channels: rules.channels,
  rawEvent: event,
  messages: rules.channels.reduce((acc, ch) => {
    acc[ch] = templates[ch] || templates.telegram_admin;
    return acc;
  }, {})
};

function buildTelegramMessage(type, data, audience) {
  const emojis = {
    job_created: '📋', job_assigned: '🔗', job_completed: '✅',
    payment_received: '💰', invoice_overdue: '⚠️', inventory_low: '📦',
    worker_absent: '❌', client_feedback: '💬', expense_submitted: '🧾',
    system_alert: '🚨'
  };
  const emoji = emojis[type] || '🔔';

  let msg = `${emoji} *${type.replace(/_/g, ' ').toUpperCase()}*\n\n`;

  if (data.description) msg += `${data.description}\n\n`;
  if (data.client_name) msg += `👤 Client: ${data.client_name}\n`;
  if (data.worker_name) msg += `👷 Worker: ${data.worker_name}\n`;
  if (data.amount) msg += `💵 Amount: $${data.amount}\n`;
  if (data.job_id || data.jobId) msg += `🔧 Job #${data.job_id || data.jobId}\n`;
  if (data.invoice_id || data.invoiceId) msg += `🧾 Invoice #${data.invoice_id || data.invoiceId}\n`;

  msg += `\n🕐 ${new Date().toLocaleString()}`;

  return msg;
}

function buildEmailMessage(type, data, audience) {
  return {
    subject: `[Kosai] ${type.replace(/_/g, ' ').toUpperCase()} - ${data.client_name || data.description || ''}`,
    body: `Event: ${type}\n\n${data.description || ''}\n\n---\nKosai Notification System\n${new Date().toISOString()}`
  };
}
